formulas.expression:
IF(
    AND(ISBLANK({!Job.India_City__c}), ISBLANK({!Job.India_State__c})),
    {!Job.India_Country__c},
    IF(
        ISBLANK({!Job.India_City__c}),
        {!Job.India_State__c} & ", " & {!Job.India_Country__c},
        IF(
            ISBLANK({!Job.India_State__c}),
            {!Job.India_City__c} & ", " & {!Job.India_Country__c},
            {!Job.India_City__c} & ", " & {!Job.India_State__c} & ", " & {!Job.India_Country__c}
        )
    )
)
